from pathlib import Path
from datetime import date, datetime, timedelta
import csv, re
logs_dir = Path('/app/logs')
ref = date(2025,8,12)
periods = [
    ('today', ref, ref),
    ('last_7_days', ref - timedelta(days=6), ref),
    ('last_30_days', ref - timedelta(days=29), ref),
    ('month_to_date', date(2025,8,1), ref),
    ('total', None, None),
]
sevs = ['ERROR','WARNING','INFO']
counts = {p:{s:0 for s in sevs} for p,_,_ in periods}
patterns = {s: re.compile(r'\[' + s + r'\]') for s in sevs}
for path in sorted(logs_dir.glob('*.log')):
    d = datetime.strptime(path.name[:10], '%Y-%m-%d').date()
    active = [name for name,start,end in periods if name=='total' or (start <= d <= end)]
    for line in path.read_text().splitlines():
        for s, pat in patterns.items():
            if pat.search(line):
                for a in active:
                    counts[a][s] += 1
                break
with open('/app/summary.csv') as f:
    actual_rows = list(csv.DictReader(f))
actual = {(r['period'], r['severity']): int(r['count']) for r in actual_rows}
for p,_,_ in periods:
    for s in sevs:
        assert actual[(p,s)] == counts[p][s], ((p,s), actual[(p,s)], counts[p][s])
print('counts_ok')
print(counts)
